import numpy as np, pandas as pd
from pathlib import Path

tickers = ['NVDA','TSM','AVGO','AMAT']
start_date, end_date = '2024-01-01', '2024-12-31'

parquet_path = Path\('C:/ai_supply_chain_trading/trading_data/news/eodhd_global_backfill.parquet'\)
